                       <div dangerouslySetInnerHTML={{ __html: selectedBlog.content }} />
                    </article>
                  </div>
                </div>
              </GlassCard>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </Section>
  );
};

