                <Shield size={16} />
              </div>
              <span className="hidden sm:inline">Sowmya.G</span>
            </a>

            {/* Desktop Nav */}
            <div className="hidden md:flex items-center gap-1">
              {navItems.map((item) => (
                <a 
                  key={item.label} 
                  href={item.href}
                  onClick={(e) => handleScroll(e, item.href)}
                  className="px-4 py-2 text-sm font-medium text-gray-600 hover:text-purple-600 hover:bg-white/50 rounded-lg transition-all cursor-pointer"
                >
                  {item.label}
                </a>
              ))}
              <a 
                href="#contact" 
                onClick={(e) => handleScroll(e, '#contact')}
                className="ml-2 px-6 py-2.5 bg-gradient-to-r from-purple-600 to-pink-600 text-white text-sm font-bold rounded-lg shadow-lg hover:shadow-purple-500/30 hover:scale-105 transition-all duration-300 cursor-pointer"
              >
                Hire Me
              </a>
            </div>

            {/* Mobile Toggle */}
            <button 
              className="md:hidden p-2 text-gray-600 pointer-events-auto hover:bg-gray-100 rounded-lg transition-colors"
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            >
              {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </motion.nav>

      {/* Mobile Menu */}
      <AnimatePresence>
        {mobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="fixed inset-0 z-40 bg-white/95 backdrop-blur-3xl pt-28 px-6 md:hidden overflow-y-auto pointer-events-auto"
          >
            <div className="flex flex-col gap-4">
              {navItems.map((item) => (
                <a
                  key={item.label}
                  href={item.href}
                  onClick={(e) => handleScroll(e, item.href)}
                  className="text-2xl font-bold text-gray-800 py-4 border-b border-gray-100 cursor-pointer hover:text-purple-600 transition-colors"
                >
                  {item.label}
                </a>
              ))}
              <a 
                href="#contact"
                onClick={(e) => handleScroll(e, '#contact')}
                className="text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-purple-600 to-pink-600 py-4 border-b border-gray-100 cursor-pointer"
              >
                Hire Me
              </a>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default Navigation;
